import requests
import time

# SMILES: Nc3nc(OCc1ccccc1)c2nc[nH]c2n3
# This looks like a purine derivative maybe a ligand for a kinase or DHFR? Actually DHFR binds dihydrofolate/methotrexate.
# Let's search RCSB for similar ligands via SMILES substructure.
smiles = "Nc3nc(OCc1ccccc1)c2nc[nH]c2n3"
# Use RCSB search API
query = {
    "query": {
        "type": "terminal",
        "service": "chemical",
        "parameters": {
            "value": smiles,
            "type": "smiles",
            "match_type": "graph-strict"
        }
    },
    "return_type": "entry"
}
try:
    r = requests.post("https://search.rcsb.org/rcsbsearch/v2/query", json=query, timeout=10)
    if r.status_code == 200:
        result = r.json()
        print("Result:", result)
        # Extract PDB IDs
        if 'result_set' in result:
            pdb_ids = [item['identifier'] for item in result['result_set']]
            print(f"Found {len(pdb_ids)} PDB entries with this ligand: {pdb_ids}")
        else:
            print("No results")
    else:
        print(f"Search failed: {r.status_code}")
except Exception as e:
    print(f"Error: {e}")











































































